import java.util.*;

class Solution {
    public int minMalwareSpread(int[][] graph, int[] initial) {
        int n = graph.length, res = 0, minSize = Integer.MAX_VALUE;
        int[] color = new int[n];
        Arrays.fill(color, -1);
        int colors = 0;

        for (int i = 0; i < n; ++i) {
            if (color[i] == -1) {
                Queue<Integer> q = new LinkedList<>();
                q.offer(i);
                color[i] = colors;

                while (!q.isEmpty()) {
                    int t = q.poll();
                    for (int j = 0; j < n; ++j) {
                        if (graph[t][j] == 1 && color[j] == -1) {
                            q.offer(j);
                            color[j] = colors;
                        }
                    }
                }
                ++colors;
            }
        }

        int[] area = new int[colors], count = new int[colors];
        Set<Integer> initiallyInfected = new HashSet<>();
        for (int i : initial) {
            initiallyInfected.add(i);
        }
        for (int i = 0; i < n; ++i) {
            ++area[color[i]];
            if (initiallyInfected.contains(i)) {
                ++count[color[i]];
            }
        }

        for (int i : initial) {
            if (count[color[i]] == 1) {
                if (area[color[i]] < minSize) {
                    minSize = area[color[i]];
                    res = i;
                } else if (area[color[i]] == minSize && i < res) {
                    res = i;
                }
            }
        }

        return res;
    }
}
